import React, { useState, useEffect } from 'react';
import axios from '../api';

const AnalyticsDashboard = ({ userId }) => {
  const [analytics, setAnalytics] = useState(null);

  useEffect(() => {
    fetchAnalytics();
  }, []);

  const fetchAnalytics = async () => {
    try {
      const res = await axios.get('/analytics/monthly?year=2024&month=1');
      setAnalytics(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  if (!analytics) return <p>Loading analytics...</p>;

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
      <div className="bg-gradient-to-r from-green-400 to-green-600 text-white p-6 rounded-xl shadow-lg text-center">
        <h3 className="text-lg font-semibold opacity-90">Savings Rate</h3>
        <p className="text-4xl font-bold">{analytics.savingsRate}%</p>
      </div>
      <div className="bg-gradient-to-r from-blue-400 to-blue-600 text-white p-6 rounded-xl shadow-lg text-center">
        <h3 className="text-lg font-semibold opacity-90">Income Std Dev</h3>
        <p className="text-4xl font-bold">${analytics.incomeStd}</p>
      </div>
      <div className="bg-gradient-to-r from-orange-400 to-orange-600 text-white p-6 rounded-xl shadow-lg text-center">
        <h3 className="text-lg font-semibold opacity-90">Budget Usage</h3>
        <p className="text-4xl font-bold">{analytics.budgetUsage}</p>
      </div>
    </div>
  );
};

export default AnalyticsDashboard;
